import React, { useState } from 'react';

const App = () => {
  const [creditScore, setCreditScore] = useState(85);
  const [displayDetails, setDisplayDetails] = useState(true);
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded shadow-md w-3/4">
        <div className="bg-[#C06C88] p-4 rounded shadow-md w-full mb-4">
          <div className="bg-[#411C56] p-4 rounded shadow-md w-full mb-4 text-white">
            <div className="flex justify-between mb-2">
              <button onClick={() => setCreditScore(creditScore + 5)}>Update</button>
              <button onClick={() => setDisplayDetails(!displayDetails)}>Toggle</button>
            </div>
            <h2>Credit Score: {creditScore}</h2>
            {displayDetails && <p>This is the credit score details.</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
